import numpy as np

def validate_1d_float64(arr):
    if arr.ndim != 1 or arr.dtype != np.float64:
        raise ValueError('expected 1d float64')
    print('ok', arr.size)

ok_arr = np.array([0.1, 0.2], dtype=np.float64)
validate_1d_float64(ok_arr)
try:
    validate_1d_float64(np.array([[1, 2]], dtype=np.int32))
except ValueError as e:
    print('| err', e)

